	"oa:hasBody": {
		"@type": "oa:TextualBody",
		"dc:format": "text/plain",
		"rdf:value": "Trousseau. Habits et linge qu'on donne à une jeune fille en se mariant, ou à\n                     un enfant qui va en pension."
	},
